function LBattleViewPoolMgr:OnDispose()
    for k,v in ipairs(self._effectList) do
        v:Dispose()
    end

    for k,v in ipairs(self._unitList) do
        v:Dispose()
    end

    for k,v in ipairs(self._dropList) do
        v:Dispose()
    end

    for k,v in ipairs(self._skillList) do
        v:Dispose()
    end
    for k,v in ipairs(self._bulletList) do
        v:Dispose()
    end


    for k,v in ipairs(self._buffList) do
        v:Dispose()
    end

    for k,v in ipairs(self._hudList) do
        v:Dispose()
    end

    for k,v in ipairs(self._headList) do
        v:Dispose()
    end

    local effectDpList = self._effectDpList
    for k, list in pairs(effectDpList) do
        for m, dp in ipairs(list) do
            dp:Dispose()
        end
        effectDpList[k] = nil
    end

    local spineDpList = self._spineDpList
    for k, list in pairs(spineDpList) do
        for m, dp in ipairs(list) do
            dp:Dispose()
        end
        spineDpList[k] = nil
    end

    local anyDpList = self._anyDpList
    for k, list in pairs(anyDpList) do
        for m, dp in ipairs(list) do
            dp:Dispose()
        end
        anyDpList[k] = nil
    end

    for k,v in ipairs(self._unitViewRootList) do
        DestroyObject(v.gameObject)
    end

    for k,v in ipairs(self._dropViewRootList) do
        DestroyObject(v.gameObject)
    end

    for k,v in ipairs(self._effectViewRootList) do
        DestroyObject(v.gameObject)
    end

    for k, v in ipairs(self._hudViewRootList) do
        DestroyObject(v.gameObject)
    end
end

