---更换场景清理一些显示对象 （只保留主角的形象和技能特效）
function LBattleViewPoolMgr:ClearWhenChangeLevel(exclude)
    local removeIdxList = {}
    local removeIdx = 0
    for k, list in pairs(self._effectDpList) do
        removeIdx = 0
        for m, dp in ipairs(list) do
            local assetPath = dp:GetAssetPath()
            if not exclude[assetPath] then
                dp:Dispose()
                removeIdx = removeIdx + 1
                removeIdxList[removeIdx] = m
            end
        end

        for m=removeIdx, 1, -1 do
            list:remove(removeIdxList[m])
        end

        if #list == 0 then
            self._effectDpList[k] = nil
        end
    end

    for k, list in pairs(self._spineDpList) do
        removeIdx = 0
        for m, dp in ipairs(list) do
            local assetPath = dp:GetAssetPath()
            if not exclude[assetPath] then
                dp:Dispose()
                removeIdx = removeIdx + 1
                removeIdxList[removeIdx] = m
            end
        end

        for m=removeIdx, 1, -1 do
            list:remove(removeIdxList[m])
        end

        if #list == 0 then
            self._spineDpList[k] = nil
        end
    end
end

