---region 回收显示对象
---@param dp LxAnyDp
function LBattleViewPoolMgr:RecycleAnyDp(dp)
    if dp:IsRecycling() then
        local assetPath = dp:GetAssetPath()
        if string.isempty(assetPath) then
            assetPath = "empty"
        end
        local list = self._anyDpList[assetPath]
        if not list then
            list = {}
            self._anyDpList[assetPath] = list
        end
        table.insert(list, dp)
        dp:SetParent(self._rootTrans, false)
        dp:SetPosition(self._zeroPos)
        dp:Recycle(self._recycleTime)
    else
        LogError("不应该进入这里")
        printError("PoolError", "战斗回收函数使用错误")
    end
end

